"use client";

import { useState, useEffect, useRef } from "react";

const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800;900&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  .hero-root {
    font-family: 'Manrope', sans-serif;
    min-height: 100vh;
    background: linear-gradient(120deg, #1b25e8 0%, #5b1fc8 45%, #7b10c8 75%, #6a0dad 100%);
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
  }

  .hero-root::before {
    content: '';
    position: absolute;
    inset: 0;
    background-image:
      radial-gradient(ellipse 80% 50% at 20% 40%, rgba(80,80,255,0.25) 0%, transparent 60%),
      radial-gradient(ellipse 60% 60% at 80% 60%, rgba(120,0,200,0.2) 0%, transparent 60%);
    pointer-events: none;
  }

  .hero-waves {
    position: absolute;
    bottom: 220px;
    left: 0;
    right: 0;
    height: 120px;
    opacity: 0.12;
    pointer-events: none;
  }

  /* ─── Navbar ─── */
  .navbar {
    position: relative;
    z-index: 20;
    padding: 18px 32px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 16px;
  }

  .nav-pill {
    display: flex;
    align-items: center;
    background: #fff;
    border-radius: 999px;
    padding: 6px 6px 6px 22px;
    gap: 4px;
    flex: 1;
    max-width: 900px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.18);
  }

  .nav-logo {
    display: flex;
    align-items: center;
    gap: 8px;
    font-weight: 900;
    font-size: 17px;
    color: #111;
    text-decoration: none;
    margin-right: 20px;
    white-space: nowrap;
    letter-spacing: -0.3px;
  }

  .logo-icon {
    width: 26px;
    height: 26px;
    background: linear-gradient(135deg, #1b25e8, #7b10c8);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }

  .nav-links {
    display: flex;
    align-items: center;
    flex: 1;
    gap: 2px;
  }

  .nav-links a {
    padding: 8px 15px;
    border-radius: 999px;
    font-size: 13.5px;
    font-weight: 500;
    color: #222;
    text-decoration: none;
    transition: background 0.18s;
    white-space: nowrap;
  }

  .nav-links a:hover, .nav-links a.active {
    background: #f2f2f2;
    font-weight: 600;
  }

  .btn-get-in-touch {
    display: flex;
    align-items: center;
    gap: 8px;
    background: linear-gradient(135deg, #5b1fc8, #7b10c8);
    color: #fff;
    border: none;
    border-radius: 999px;
    padding: 12px 22px;
    font-size: 13.5px;
    font-weight: 700;
    cursor: pointer;
    text-decoration: none;
    white-space: nowrap;
    transition: opacity 0.18s, transform 0.18s;
    font-family: 'Manrope', sans-serif;
    margin-left: auto;
  }

  .btn-get-in-touch:hover { opacity: 0.88; transform: translateY(-1px); }

  /* ─── Hero Content ─── */
  .hero-body {
    position: relative;
    z-index: 10;
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 36px 24px 0;
    text-align: center;
  }

  .badge {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: rgba(255,255,255,0.13);
    border: 1.5px solid rgba(255,255,255,0.28);
    backdrop-filter: blur(8px);
    border-radius: 999px;
    padding: 7px 20px;
    font-size: 12.5px;
    font-weight: 600;
    color: #fff;
    margin-bottom: 22px;
    animation: fadeSlideDown 0.6s ease both;
  }

  .badge-pulse {
    width: 18px;
    height: 11px;
    opacity: 0.9;
  }

  .hero-title {
    font-size: clamp(34px, 5.2vw, 68px);
    font-weight: 900;
    color: #fff;
    line-height: 1.1;
    max-width: 800px;
    margin-bottom: 30px;
    letter-spacing: -1.5px;
    animation: fadeSlideUp 0.6s 0.12s ease both;
  }

  .btn-services {
    display: inline-flex;
    align-items: center;
    gap: 10px;
    background: rgba(255,255,255,0.15);
    border: 2px solid rgba(255,255,255,0.75);
    color: #fff;
    border-radius: 999px;
    padding: 13px 32px;
    font-size: 14.5px;
    font-weight: 700;
    cursor: pointer;
    text-decoration: none;
    transition: background 0.2s, transform 0.2s;
    font-family: 'Manrope', sans-serif;
    animation: fadeSlideUp 0.6s 0.22s ease both;
    backdrop-filter: blur(6px);
  }

  .btn-services:hover {
    background: rgba(255,255,255,0.25);
    transform: translateY(-2px);
  }

  /* ─── Parallelogram Image Strip ─── */
  .strip-wrapper {
    position: relative;
    z-index: 10;
    width: 100%;
    height: 280px;
    overflow: hidden;
    margin-top: 44px;
  }

  .strip-inner {
    display: flex;
    width: 100%;
    height: 100%;
  }

  .para-slot {
    position: relative;
    flex: 1;
    overflow: hidden;
    clip-path: polygon(8% 0%, 100% 0%, 92% 100%, 0% 100%);
    margin-right: -18px;
  }

  .para-slot:first-child {
    clip-path: polygon(0% 0%, 100% 0%, 92% 100%, 0% 100%);
  }

  .para-slot:last-child {
    clip-path: polygon(8% 0%, 100% 0%, 100% 100%, 0% 100%);
    margin-right: 0;
  }

  .para-img {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
    filter: brightness(0.82) saturate(1.15);
    transition: opacity 0.8s ease, transform 0.8s ease;
  }

  .para-img.visible {
    opacity: 1;
    transform: scale(1);
  }

  .para-img.leaving {
    opacity: 0;
    transform: scale(0.97);
  }

  .para-img.entering {
    opacity: 0;
    transform: scale(1.05);
  }

  .para-slot::after {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(180deg, rgba(26,26,200,0.18) 0%, transparent 60%);
    pointer-events: none;
    z-index: 2;
  }

  /* Decorative diagonal outline */
  .deco-outline {
    position: absolute;
    top: 16px;
    right: 56px;
    width: 190px;
    height: 248px;
    border: 1.5px solid rgba(255,255,255,0.32);
    transform: skewX(-14deg);
    pointer-events: none;
    z-index: 15;
  }

  /* Progress dots */
  .slide-dots {
    position: absolute;
    bottom: 14px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    gap: 6px;
    z-index: 20;
  }

  .dot {
    height: 6px;
    border-radius: 999px;
    background: rgba(255,255,255,0.35);
    transition: width 0.35s ease, background 0.35s ease;
    cursor: pointer;
    width: 6px;
  }

  .dot.active {
    width: 24px;
    background: #fff;
  }

  /* Progress bar */
  .progress-bar {
    position: absolute;
    bottom: 0;
    left: 0;
    height: 3px;
    background: rgba(255,255,255,0.5);
    z-index: 20;
    transform-origin: left;
  }

  @keyframes progress {
    from { width: 0%; }
    to   { width: 100%; }
  }

  .progress-bar.running {
    animation: progress 6s linear;
  }

  /* ─── Stats Bar ─── */
  .stats-bar {
    position: relative;
    z-index: 10;
    display: flex;
    align-items: center;
    padding: 0 48px;
    height: 80px;
    background: rgba(0,0,0,0.22);
    backdrop-filter: blur(12px);
    border-top: 1px solid rgba(255,255,255,0.1);
  }

  .stat {
    display: flex;
    flex-direction: column;
    gap: 3px;
    padding-right: 56px;
  }

  .stat-divider {
    width: 1px;
    height: 36px;
    background: rgba(255,255,255,0.2);
    margin-right: 56px;
    flex-shrink: 0;
  }

  .stat-num {
    font-size: 22px;
    font-weight: 900;
    color: #fff;
    letter-spacing: -0.5px;
    line-height: 1;
  }

  .stat-lbl {
    font-size: 11px;
    font-weight: 500;
    color: rgba(255,255,255,0.5);
    text-transform: uppercase;
    letter-spacing: 0.8px;
  }

  .play-reel {
    margin-left: auto;
    display: flex;
    align-items: center;
    gap: 14px;
    cursor: pointer;
    text-decoration: none;
  }

  .play-reel-label {
    font-size: 14px;
    font-weight: 700;
    color: #fff;
  }

  .play-btn {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    border: 2px solid rgba(255,255,255,0.55);
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.2s, border-color 0.2s;
    flex-shrink: 0;
  }

  .play-reel:hover .play-btn {
    background: rgba(255,255,255,0.15);
    border-color: #fff;
  }

  /* ─── Animations ─── */
  @keyframes fadeSlideDown {
    from { opacity: 0; transform: translateY(-14px); }
    to   { opacity: 1; transform: translateY(0); }
  }

  @keyframes fadeSlideUp {
    from { opacity: 0; transform: translateY(20px); }
    to   { opacity: 1; transform: translateY(0); }
  }

  @media (max-width: 900px) {
    .nav-links { display: none; }
    .hero-title { font-size: 36px; letter-spacing: -1px; }
    .strip-wrapper { height: 200px; }
    .stats-bar { padding: 0 20px; }
    .stat { padding-right: 28px; }
    .stat-divider { margin-right: 28px; }
  }

  @media (max-width: 600px) {
    .navbar { padding: 12px 16px; }
    .deco-outline { display: none; }
    .stats-bar { flex-wrap: wrap; height: auto; padding: 14px 16px; gap: 12px; }
  }
`;

// 4 image-sets × 4 slots
const IMAGE_SETS = [
  [
    "https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1553877522-43269d4ea984?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=500&h=400&fit=crop",
  ],
  [
    "https://images.unsplash.com/photo-1515187029135-18ee286d815b?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1504384308090-c894fdcc538d?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1560472355-536de3962603?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1556761175-5973dc0f32e7?w=500&h=400&fit=crop",
  ],
  [
    "https://images.unsplash.com/photo-1551836022-deb4988cc6c0?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1497366216548-37526070297c?w=500&h=400&fit=crop",
  ],
  [
    "https://images.unsplash.com/photo-1521737711867-e3b97375f902?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1498050108023-c5249f4df085?w=500&h=400&fit=crop",
    "https://images.unsplash.com/photo-1531482615713-2afd69097998?w=500&h=400&fit=crop",
  ],
];

export default function HeroSection() {
  const [current, setCurrent] = useState(0);
  const [phase, setPhase] = useState("visible");
  const [progressKey, setProgressKey] = useState(0);
  const nextIdx = useRef(0);

  const transition = (to) => {
    if (to === current) return;
    nextIdx.current = to;
    setPhase("leaving");
    setTimeout(() => {
      setCurrent(to);
      setProgressKey((k) => k + 1);
      setPhase("entering");
      // tiny frame delay so browser paints "entering" before "visible"
      requestAnimationFrame(() => {
        requestAnimationFrame(() => setPhase("visible"));
      });
    }, 750);
  };

  // Auto-advance every 6 seconds
  useEffect(() => {
    const timer = setInterval(() => {
      transition((current + 1) % IMAGE_SETS.length);
    }, 6000);
    return () => clearInterval(timer);
  }, [current]);

  const imgs = IMAGE_SETS[current];

  return (
    <>
      <style>{STYLES}</style>
      <section className="hero-root">

        {/* Wavy bg decoration */}
        <svg className="hero-waves" viewBox="0 0 1440 120" preserveAspectRatio="none">
          <path d="M0,60 C360,120 720,0 1080,60 C1260,90 1380,40 1440,60 L1440,120 L0,120Z"
            fill="rgba(255,255,255,0.06)" />
          <path d="M0,80 C400,20 800,100 1200,40 L1440,60 L1440,120 L0,120Z"
            fill="rgba(255,255,255,0.04)" />
        </svg>

        {/* ── Navbar ── */}
        <nav className="navbar">
          <div className="nav-pill">
            <a href="#" className="nav-logo">
              <div className="logo-icon">
                <svg viewBox="0 0 14 14" fill="none" width="14" height="14">
                  <circle cx="7" cy="7" r="5" stroke="white" strokeWidth="1.8" />
                  <circle cx="7" cy="7" r="2" fill="white" />
                </svg>
              </div>
              Socioly
            </a>
            <div className="nav-links">
              <a href="#" className="active">Home</a>
              <a href="#">About</a>
              <a href="#">Services</a>
              <a href="#">Pricing</a>
              <a href="#">Blog</a>
              <a href="#">Contact</a>
            </div>
            <a href="#" className="btn-get-in-touch">
              Get in Touch
              <svg width="13" height="13" viewBox="0 0 13 13" fill="none">
                <path d="M2 11L11 2M11 2H5M11 2v6" stroke="white" strokeWidth="2"
                  strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </a>
          </div>
        </nav>

        {/* ── Hero Copy ── */}
        <div className="hero-body">
          <div className="badge">
            <svg className="badge-pulse" viewBox="0 0 32 20" fill="none">
              <polyline points="0,10 6,10 9,2 13,18 17,6 21,14 25,10 32,10"
                stroke="white" strokeWidth="2.5" fill="none"
                strokeLinecap="round" strokeLinejoin="round" />
            </svg>
            Empowering Your Business with Data-Driven Marketing
          </div>

          <h1 className="hero-title">
            Empowering Your Business<br />
            with Data&#8209;Driven Marketing
          </h1>

          <a href="#" className="btn-services">
            Our Services
            <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
              <path d="M2.5 12.5L12.5 2.5M12.5 2.5H5.5M12.5 2.5v7"
                stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </a>
        </div>

        {/* ── Parallelogram Strip ── */}
        <div className="strip-wrapper">
          <div className="strip-inner">
            {[0, 1, 2, 3].map((i) => (
              <div key={i} className="para-slot">
                <img
                  src={imgs[i]}
                  alt={`team-${i}`}
                  className={`para-img ${phase}`}
                  style={{ transitionDelay: `${i * 70}ms` }}
                />
              </div>
            ))}
          </div>

          {/* Decorative outline */}
          <div className="deco-outline" />

          {/* Dots */}
          <div className="slide-dots">
            {IMAGE_SETS.map((_, i) => (
              <div
                key={i}
                className={`dot ${i === current ? "active" : ""}`}
                onClick={() => transition(i)}
              />
            ))}
          </div>

          {/* Progress bar */}
          <div
            key={progressKey}
            className="progress-bar running"
            style={{ animationDuration: "6s" }}
          />
        </div>

        {/* ── Stats Bar ── */}
        <div className="stats-bar">
          <div className="stat">
            <span className="stat-num">20.5K</span>
            <span className="stat-lbl">Projects Done</span>
          </div>
          <div className="stat-divider" />
          <div className="stat">
            <span className="stat-num">100.5K</span>
            <span className="stat-lbl">Happy Clients</span>
          </div>
          <div className="stat-divider" />
          <div className="stat">
            <span className="stat-num">150.5K</span>
            <span className="stat-lbl">Team Members</span>
          </div>

          <a href="#" className="play-reel">
            <span className="play-reel-label">Play Reel</span>
            <div className="play-btn">
              <svg width="14" height="14" viewBox="0 0 14 14" fill="white">
                <path d="M3 2L12 7L3 12V2Z" />
              </svg>
            </div>
          </a>
        </div>

      </section>
    </>
  );
}


